def gen(rng, size):
    k = rng.randint(1, 6)
    groups = max(1, size // k)
    nums = []
    for _ in range(groups):
        start = rng.randint(1, 10**9 - k)
        for d in range(k):
            nums.append(start + d)
    rng.shuffle(nums)
    return [nums, k]

