class Solution:
    def isPossibleDivide(self, nums, k):
        if len(nums) % k != 0:
            return False
        from collections import Counter
        cnt = Counter(nums)
        for v in sorted(nums):
            if cnt[v] == 0:
                continue
            need = cnt[v]
            for d in range(k):
                if cnt[v + d] < need:
                    return False
                cnt[v + d] -= need
        return True

