class Solution:
    def isPossibleDivide(self, nums, k):
        if len(nums) % k != 0:
            return False
        from collections import Counter
        import heapq
        cnt = Counter(nums)
        heap = list(cnt.keys())
        heapq.heapify(heap)
        while heap:
            start = heap[0]
            c = cnt[start]
            if c == 0:
                heapq.heappop(heap)
                continue
            for d in range(k):
                v = start + d
                if cnt[v] < c:
                    return False
                cnt[v] -= c
        return True

