var isPossibleDivide = function(nums, k) {
    if (nums.length % k !== 0) return false;
    const cnt = new Map();
    for (const v of nums) cnt.set(v, (cnt.get(v) || 0) + 1);
    const keys = [...cnt.keys()].sort((a, b) => a - b);
    for (const start of keys) {
        const c = cnt.get(start);
        if (c === 0) continue;
        for (let d = 0; d < k; d++) {
            const v = start + d;
            const have = cnt.get(v) || 0;
            if (have < c) return false;
            cnt.set(v, have - c);
        }
    }
    return true;
};
